import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { verifyToken } from '@/lib/auth';

// GET /api/admin/pages/[id] - Get single page
export async function GET(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const page = await prisma.page.findUnique({
      where: { id: params.id },
    });

    if (!page) {
      return NextResponse.json({ error: 'Page not found' }, { status: 404 });
    }

    // Parse sections JSON
    const pageData = {
      ...page,
      sections: page.sections ? JSON.parse(page.sections) : [],
    };

    return NextResponse.json({ success: true, page: pageData });
  } catch (error) {
    console.error('Page GET error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

// PUT /api/admin/pages/[id] - Update page
export async function PUT(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const data = await request.json();
    
    // Check if slug is being updated and if it's unique
    if (data.slug) {
      const existingPage = await prisma.page.findUnique({
        where: { slug: data.slug }
      });
      
      // If slug exists and it's not the current page, return error
      if (existingPage && existingPage.id !== params.id) {
        return NextResponse.json(
          { error: 'Slug already exists. Please choose a different slug.' },
          { status: 400 }
        );
      }
    }
    
    const updateData: any = {
      title: data.title,
      slug: data.slug,
      status: data.status,
      metaTitle: data.metaTitle,
      metaDescription: data.metaDescription,
      sections: data.sections ? JSON.stringify(data.sections) : undefined,
      updatedAt: new Date(),
    };
    
    // اگر language تغییر کرده، آپدیت کن
    if (data.language) {
      updateData.language = data.language;
    }
    
    const page = await prisma.page.update({
      where: { id: params.id },
      data: updateData,
    });

    console.log('Page updated:', { id: page.id, status: page.status });

    return NextResponse.json({ success: true, page });
  } catch (error) {
    console.error('Page PUT error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

// DELETE /api/admin/pages/[id] - Delete page
export async function DELETE(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // دریافت اطلاعات صفحه قبل از حذف
    const page = await prisma.page.findUnique({
      where: { id: params.id },
      select: { pageGroupId: true }
    });

    // حذف صفحه
    await prisma.page.delete({
      where: { id: params.id },
    });

    // اگر صفحه در گروهی بود، بررسی کن که آیا گروه خالی شده
    if (page?.pageGroupId) {
      const remainingPages = await prisma.page.count({
        where: { pageGroupId: page.pageGroupId }
      });
      
      // اگر هیچ صفحهای در گروه نمانده، گروه را حذف کن
      if (remainingPages === 0) {
        await prisma.pageGroup.delete({
          where: { id: page.pageGroupId }
        });
        console.log(`Deleted empty page group: ${page.pageGroupId}`);
      }
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Page DELETE error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}